var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"올바른 보도, 진실된 정보. 그로니아 국영 뉴스. 방금 들어온 속보입니다.","JPN":"正しい報道、真なる情報。グロニア国営ニュース。ただいま入ってきた速報です。","ENG":"Reporting in with the truth, Gronia National News. Breaking news.","TWN":"真實的報導，正確的資訊，格羅尼亞國境新聞。 現在為您插播一則快訊。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"보안국은 청사를 습격한 신원 불명의 용병에 대해 공개 수배령을 내렸습니다.","JPN":"保安局は庁舎を襲撃した身元不明の傭兵について、公開手配しました。","ENG":"The Department of National Security has issued a bounty for the unidentified mercenary attacking its main office.","TWN":"安全局已經針對襲擊安全局大樓的傭兵發布通緝令。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"비슷한 인상착의의 인물을 목격하신 분께서는 보안국 및 경찰, 수도 방위 부대에 연락 바랍니다.","JPN":"似たような人相の人物を目撃した方は、保安局及び警察、首都防衛部隊までご連絡ください。","ENG":"Anyone who has any information or has seen someone with a similar description as the mercenary should contact the Department of National Security, police, or Capital Defense Unit.","TWN":"民眾若有發現類似穿著的人物，請盡速通報安全局、警察局，或是首都防衛隊。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"한편, 정부는 긴급 기자 회견을 통해 건국절 기념식을 강행하겠다는 의사를 표명했습니다.","JPN":"一方、政府は緊急記者会見で建国記念式を強行するという意を表明しました。","ENG":"Meanwhile, the government expressed its intention to go ahead with the National Foundation Day ceremony via an emergency press conference.","TWN":"另一方面，政府緊急召開記者會，表示國慶典禮將如期舉行。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"건국 선언식이 있었던 자정부터 시작되는 행사는, 동이 틀 무렵 열릴 공연회를 끝으로 그 대미를 장식하게 됩니다.","JPN":"建国宣言式が行われた午前0時から始まる行事は、明け方、最後を飾る公演会の後、幕を下ろす予定です。","ENG":"The event, starting at midnight, which was when the founding ceremony was originally held, will end with a concert at dawn.","TWN":"整個國慶活動從發表建國宣言的子夜開始，最後以黎明時分的演奏會作為完美的結束。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"타나베린의 시민들은 이른 시각부터 퍼레이드가 열릴 중앙로에 앞다퉈 모여 국기를 흔들고 있습니다.","JPN":"タナベリンの市民は早朝からパレードが始まる中央通りへ集まり、国旗を振っています。","ENG":"Citizens of Tanaberin have been gathering since early in the morning to wave flags on the central road where the parade will be held.","TWN":"而預備要舉行遊行的中央路上，一早就聚集大群達那貝林的市民揮舞著國旗。"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"시민들이 제창하는 국가를 들어 보십시오. 이것이야말로 우리나라의 기상, 우리나라의 미래…….","JPN":"市民の歌う国歌をお聞きください。これこそ我が国の気性、我が国の未来……","ENG":"Listen to the sound of these citizens singing the national anthem. This is the spirit of our country, the future of our country...","TWN":"請看看市民們揮舞著國旗的盛況，這才是我們國家最美的景色，國家的未來……"},"stage":{"bg":"HARMONY_01_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아. 간만에 인사하네요, 상상 친구 씨.","JPN":"あ。久しぶりだね、エア友さん。","ENG":"Ah. It’s been a while, hasn’t it, Mr. Imaginary Friend?","TWN":"哇，好久不見啦，我想像中的朋友。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"터무니없는 사람들이랑 엮이는 바람에 정신적으로 힘들었거든요.","JPN":"とんでもない人たちに巻き込まれて、精神的にしんどかったんだよね。","ENG":"I’ve really been under a lot of mental stress these days because I’ve been caught up with some ridiculous people.","TWN":"被那些莫名其妙的人搞得真的心好累喔。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이야. 모난 구석 안 보이려고 그렇게 애썼는데, 이번 한 방으로 텄네요. 텄어.","JPN":"いやぁ。あんなに角が立たないように頑張ったのに、今度の一発でパーだよ。パー。","ENG":"I tried so hard not to stick out, but all that effort was for nothing.","TWN":"虧我已經盡量抱持低調，結果現在都露餡兒啦！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭘 그렇게 중얼거려? 누구랑 통화하니?","JPN":"何をそんなにブツブツ言ってるの？　誰かと電話中？","ENG":"What are you mumbling about? Are you making a call or something?","TWN":"你在自言自語什麼？還是你在跟誰講電話？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"흐익?!","JPN":"ひいっ！？","ENG":"Hwagh?!","TWN":"嚇？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"왜 그래? 갑자기 말을 걸어서 놀랐으려나?","JPN":"どうしたの？　いきなり話しかけられてびっくりしちゃった？","ENG":"Huh? What's wrong? Did I surprise you?","TWN":"幹嘛？我突然跟你說話嚇到你嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 네……. 그야 기척도 없이 다가오셨으니까요.","JPN":"あ、はい……そりゃあ気配もなく近づいてこられたので。","ENG":"Oh, yeah... You snuck up on me.","TWN":"喔，對啊……誰叫你一聲不響地冒出來。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……그보다, 전 사람이랑 부대끼는 취미는 없어서요.","JPN":"……それより私、あまり人と馴れ馴れしくする趣味はないんです。","ENG":"...More than that, I don’t like being around people.","TWN":"……然後，我不喜歡和人太靠近，"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"다음부터는 가급적 안전 거리를 지켜 주시면 좋겠는데요.","JPN":"次からはなるべく安全距離を取っていただきたいんですけど。","ENG":"Please keep a safe distance as much as possible from now on.","TWN":"下次可以麻煩你保持社交安全距離嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};